import { createSlice } from "@reduxjs/toolkit";
import { nanoid } from "nanoid";

const filtered = (key, todo) => {
  todo.validFilter = false

  if (key === 'all') {
    todo.validFilter = true
  }
  if (key === 'completed' && todo.completed) {
    todo.validFilter = true
  }
  if (key === 'uncompleted' && !todo.completed) {
    todo.validFilter = true
  }

  return t
}

const todoSlice = createSlice({
  name: 'todos',
  initialState: {
    todos: [],
    keyFilter: 'all',
  },

  reducers: {
    addTodo(state, action) {
      const task = {
        id: nanoid(),
        text: action.payload,
        completed: false,
        validFilter: false,
      }

      const modNewTodo = filtered(state.keyFilter, task)
      console.log(modNewTodo)
      state.todos.push(modNewTodo)
    },

    removeTodo(state, action) {
      console.log('remove')
      state.todos = state.todos.filter((task) => task.id !== action.payload)
    },

    toggleTask(state, action) {
      const editTodo = state.todos.find(task => task.id === action.payload)
      editTodo.completed = !editTodo.completed

      console.log('toggle')
      filtered(state.keyFilter, editTodo)
    },

    filterTask(state, action) {
      state.keyFilter = action.payload.key
      state.todos = state.todos.map(task => {
        console.log('filter')
        return filtered(state.keyFilter, task)
      })
    }
  }
})

export const { addTodo, removeTodo, toggleTask, filterTask } = todoSlice.actions
export default todoSlice.reducer
